static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvDepthwiseSeparable2dCustomTilingData tiling;

    // Shapes
    const auto *x_shape = context->GetInputShape(0);
    const auto *w_pw_shape = context->GetInputShape(2);

    const uint32_t n = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t cIn = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t h = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t w = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    // pointwise weight: [Cout, Cin, 1, 1]
    const uint32_t cOut = static_cast<uint32_t>(w_pw_shape->GetOriginShape().GetDim(0));

    // Simple and conservative tiling
    uint32_t ocChunk = cOut < 32u ? cOut : 32u;
    if (ocChunk == 0u) ocChunk = 1u;

    uint32_t segLen = 128u;
    if (segLen > w) segLen = w;

    const uint32_t segsPerRow = CeilDiv(w, segLen);
    const uint64_t totalUnits64 = static_cast<uint64_t>(n) * static_cast<uint64_t>(h) * static_cast<uint64_t>(segsPerRow);
    uint32_t totalUnits = totalUnits64 > 0xFFFFFFFFull ? 0xFFFFFFFFu : static_cast<uint32_t>(totalUnits64);

    uint32_t blockDim = totalUnits;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_n(n);
    tiling.set_cIn(cIn);
    tiling.set_h(h);
    tiling.set_w(w);
    tiling.set_cOut(cOut);
    tiling.set_segLen(segLen);
    tiling.set_segsPerRow(segsPerRow);
    tiling.set_ocChunk(ocChunk);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

